import(""./src/utils/videoMetadata.js"").then(async ({ VideoMetadataExtractor }) => {
  const extractor = new VideoMetadataExtractor();
  const filePath = ''../storage/www/record/live/12eb90d2-c6f6-4ced-a312-92df308b7246/2025-08-22/2025-08-22-17-22-21-0.mp4'';

