import { createClient } from ''@supabase/supabase-js'';
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);

console.log(''🔍 Verificando backoff timing...'');

const { data: recordings } = await supabase
  .from(''recordings'')
  .select(''id, filename, upload_status, upload_attempts, updated_at'')
  .eq(''upload_status'', ''queued'')
  .order(''created_at'', { ascending: true });

if (recordings && recordings.length > 0) {
  recordings.forEach(rec => {
    const lastAttemptTime = new Date(rec.updated_at).getTime();
    const now = Date.now();
    const timeSinceLastAttempt = now - lastAttemptTime;
    const minutesSince = Math.round(timeSinceLastAttempt / 1000 / 60);

    console.log(''📊 Gravação:'', rec.id);
    console.log(''   Upload Attempts:'', rec.upload_attempts || 0);
    console.log(''   Last Updated:'', new Date(rec.updated_at).toLocaleString(''pt-BR''));
    console.log(''   Minutes Since:'', minutesSince);

    // Calcular backoff delay baseado no código
    const attempts = rec.upload_attempts || 0;
    const delays = [
      60 * 1000,        // 1 minute
      5 * 60 * 1000,    // 5 minutes  
      15 * 60 * 1000,   // 15 minutes
      60 * 60 * 1000,   // 1 hour
      2 * 60 * 60 * 1000, // 2 hours
      4 * 60 * 60 * 1000  // 4 hours
    ];

    const index = Math.min(attempts, delays.length - 1);
    const baseDelay = delays[index];
    const backoffMinutes = Math.round(baseDelay / 1000 / 60);
    const isReady = timeSinceLastAttempt >= baseDelay;

    console.log(''   Backoff Delay:'', backoffMinutes + '' minutos'');
    console.log(''   Ready for retry:'', isReady ? ''✅ SIM'' : ''❌ NÃO'');
    console.log('''');
  });
} else {
  console.log(''❌ Nenhuma gravação com status queued encontrada'');
}
")

