Bash(WASABI_ACCESS_KEY=8WBR4YFE79UA94TBIEST WASABI_SECRET_KEY=A9hNRDUEzcyhUtzp0SAE51IgKcJtsP1b7knZNe5W WASABI_BUCKET=safe-cameras-03 WASABI_REGION=us-east-2 WASABI_ENDPOINT=https://s3.us-east-2.wasabisys.com node -e "
import S3Service from ''./backend/src/services/S3Service.js'';

console.log(''🔍 Testando presigned URL com GET request...'');

const s3Key = ''recordings/2025/08/22/12eb90d2-c6f6-4ced-a312-92df308b7246/2025-08-22-05-50-03-0.mp4'';

try {
  const presignedUrl = await S3Service.getSignedUrl(s3Key, {
    expiresIn: 3600,
    responseHeaders: {
      contentType: ''video/mp4''
    }
  });

  console.log(''✅ URL gerada com sucesso'');

  // Testar com GET request e leitura parcial
  console.log(''\n🌐 Testando com GET request (primeiros 1KB)...'');
  const response = await fetch(presignedUrl, {
    method: ''GET'',
    headers: {
      ''Range'': ''bytes=0-1023''
    }
  });

  console.log(''   Status:'', response.status);
  console.log(''   Status Text:'', response.statusText);
  console.log(''   Content-Type:'', response.headers.get(''content-type''));
  console.log(''   Content-Length:'', response.headers.get(''content-length''));
  console.log(''   Accept-Ranges:'', response.headers.get(''accept-ranges''));

  if (response.ok || response.status === 206) {
    console.log(''✅ SUCESSO! Presigned URL está funcionando!'');

    const data = await response.arrayBuffer();
    const dataView = new DataView(data);

    // Verificar se é arquivo MP4 válido (deve começar com ftyp)
    let signature = '''';
    for (let i = 4; i < 8; i++) {
      signature += String.fromCharCode(dataView.getUint8(i));
    }

    console.log(''   Signature do arquivo:'', signature);
    if (signature === ''ftyp'') {
      console.log(''   ✅ Arquivo MP4 válido detectado!'');
    }
  } else {
    console.log(''❌ Ainda falhando:'', response.status, response.statusText);
  }

} catch (error) {
  console.error(''💥 Erro:'', error.message);
}
")
